impl Solution { pub fn num_of_minutes(n: i32, head_id: i32, manager: Vec<i32>, inform_time: Vec<i32>) -> i32 { let (mut black_adj, mut black_q, mut black_res) = (vec![vec![]; n as usize], std::collections::VecDeque::from([(head_id as usize, 0)]), 0); for (black_i, &black_m) in manager.iter().enumerate() { if black_m != -1 { black_adj[black_m as usize].push(black_i); } } while let Some((black_u, black_t)) = black_q.pop_front() { black_res = black_res.max(black_t); for &black_v in &black_adj[black_u] { black_q.push_back((black_v, black_t + inform_time[black_u])); } } black_res } }